import{_ as t,a as e,b as i,c as l,d as r,e as d,f as o,g as s}from"./chunks/无关系记录重新申请.D_1qirb1.js";import{_ as p,o as n,c as h,a2 as c}from"./chunks/framework.DnrXFDHb.js";const P=JSON.parse('{"title":"フェデレーション分散インデックス","description":"","frontmatter":{},"headers":[],"relativePath":"ja-JP/Other/federated-distributed-index.md","filePath":"ja-JP/Other/federated-distributed-index.md","lastUpdated":1781962217000}'),b={name:"ja-JP/Other/federated-distributed-index.md"};function u(m,a,_,g,x,f){return n(),h("div",null,[...a[0]||(a[0]=[c('<h1 id="フェデレーション分散インデックス" tabindex="-1">フェデレーション分散インデックス <a class="header-anchor" href="#フェデレーション分散インデックス" aria-label="Permalink to &quot;フェデレーション分散インデックス&quot;">​</a></h1><p>フェデレーション分散インデックスは、複数の ImgBed サイト同士でファイル一覧を共有するための機能です。</p><p>できることは大きく次の 3 つです。</p><ul><li>自分の一部フォルダを他のサイトに共有する。</li><li>他のノードに参加し、相手が共有したファイル一覧を自分の管理画面に同期する。</li><li>共有ファイルを閲覧、検索、プレビュー、リンクコピーに使う。自分の保存先へ再アップロードする機能ではありません。</li></ul><h2 id="設定場所" tabindex="-1">設定場所 <a class="header-anchor" href="#設定場所" aria-label="Permalink to &quot;設定場所&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>システム設定 -&gt; その他の設定 -&gt; フェデレーション分散インデックス</span></span></code></pre></div><p><img src="'+t+`" alt="ローカルノード" loading="lazy"></p><p>画面は 3 つのタブに分かれています。</p><table tabindex="0"><thead><tr><th>タブ</th><th>用途</th></tr></thead><tbody><tr><td>ローカルノード</td><td>自分の共有設定、公開ドメイン、共有フォルダ、送信インデックスを管理</td></tr><tr><td>参加中のノード</td><td>自分が参加している他サイトのノードを管理</td></tr><tr><td>参加申請</td><td>他の人から自分のノードへの参加申請を管理</td></tr></tbody></table><h2 id="初回設定" tabindex="-1">初回設定 <a class="header-anchor" href="#初回設定" aria-label="Permalink to &quot;初回設定&quot;">​</a></h2><ol><li>「ローカルノード」を開きます。</li><li>「有効」をオンにします。</li><li>「同期フォルダ」で共有したいフォルダを選びます。</li><li>「送信インデックスを更新」をクリックします。</li><li>ドメイン変更の確認が出た場合は、現在のドメインが本番用か確認して続行します。</li></ol><p>同期フォルダは複数選択できます。空にした場合は、全フォルダを共有する扱いになります。</p><h2 id="ローカルノード" tabindex="-1">ローカルノード <a class="header-anchor" href="#ローカルノード" aria-label="Permalink to &quot;ローカルノード&quot;">​</a></h2><h3 id="公開ドメイン" tabindex="-1">公開ドメイン <a class="header-anchor" href="#公開ドメイン" aria-label="Permalink to &quot;公開ドメイン&quot;">​</a></h3><p>公開ドメインは、他のノードがあなたのサイトへアクセスするときの URL です。</p><p>通常はシステムが自動で判定するため、手入力は不要です。初回更新時やドメイン変更時に確認メッセージが表示されます。</p><h3 id="同期フォルダ" tabindex="-1">同期フォルダ <a class="header-anchor" href="#同期フォルダ" aria-label="Permalink to &quot;同期フォルダ&quot;">​</a></h3><p>同期フォルダで、どのファイルを共有対象にするかを決めます。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/1/</span></span>
<span class="line"><span>/2/</span></span></code></pre></div><p>このように指定した場合、相手はこの 2 つのディレクトリ内のファイルだけを同期できます。</p><h3 id="送信インデックスを更新" tabindex="-1">送信インデックスを更新 <a class="header-anchor" href="#送信インデックスを更新" aria-label="Permalink to &quot;送信インデックスを更新&quot;">​</a></h3><p>自分が他のノードへ公開するファイル一覧を更新します。</p><p>次のタイミングで使います。</p><ul><li>フェデレーションを初めて有効にしたとき。</li><li>共有したいファイルを新しくアップロードしたとき。</li><li>同期フォルダを変更したとき。</li><li>公開ドメインを変更したとき。</li></ul><h2 id="他のノードに参加する" tabindex="-1">他のノードに参加する <a class="header-anchor" href="#他のノードに参加する" aria-label="Permalink to &quot;他のノードに参加する&quot;">​</a></h2><p>「参加中のノード」は、他の ImgBed ノードを購読する場所です。</p><p><img src="`+e+'" alt="参加中のノード" loading="lazy"></p><ol><li>相手から招待リンクを受け取ります。</li><li>入力欄に貼り付けます。</li><li>「参加申請」をクリックします。</li><li>相手の管理画面で承認されるのを待ちます。</li></ol><p>承認後、「受信インデックスを更新」すると相手の共有ファイル一覧が同期されます。</p><p><img src="'+i+'" alt="インデックス更新" loading="lazy"></p><h2 id="自分のノードへの申請を処理する" tabindex="-1">自分のノードへの申請を処理する <a class="header-anchor" href="#自分のノードへの申請を処理する" aria-label="Permalink to &quot;自分のノードへの申請を処理する&quot;">​</a></h2><p><img src="'+l+'" alt="参加申請" loading="lazy"></p><p>招待リンクを作るには、ローカルノードを有効にし、一度「送信インデックスを更新」して公開ドメインを確認してから、「招待リンクをリセット」をクリックします。</p><p>申請が届いたら、次の操作を選べます。</p><table tabindex="0"><thead><tr><th>操作</th><th>内容</th></tr></thead><tbody><tr><td>承認</td><td>相手があなたの共有ファイル一覧を同期できるようにします</td></tr><tr><td>拒否</td><td>参加を許可しません</td></tr><tr><td>削除</td><td>終了した記録を削除します</td></tr><tr><td>状態確認</td><td>相手側が関係を維持しているか確認します</td></tr></tbody></table><p>承認後、相手側でも受信インデックスの更新が必要です。</p><p><img src="'+r+'" alt="承認" loading="lazy"></p><h2 id="メッセージ" tabindex="-1">メッセージ <a class="header-anchor" href="#メッセージ" aria-label="Permalink to &quot;メッセージ&quot;">​</a></h2><p>承認済みの関係では、ノードカードからメッセージを送れます。</p><p>メッセージは連絡用であり、ファイル、タグ、ディレクトリ、アクセス権には影響しません。</p><p><img src="'+d+'" alt="メッセージ" loading="lazy"></p><h2 id="共有ファイルを見る" tabindex="-1">共有ファイルを見る <a class="header-anchor" href="#共有ファイルを見る" aria-label="Permalink to &quot;共有ファイルを見る&quot;">​</a></h2><p>同期が終わったら管理画面のファイル一覧に戻ります。上部でローカルファイルとフェデレーションファイルを切り替えられます。</p><p>フェデレーションファイルは外部ノードの一覧なので、自分のサイト上で移動、削除、タグ変更、バックアップはできません。</p><p><img src="'+o+'" alt="管理画面での表示" loading="lazy"></p><h2 id="よくある質問" tabindex="-1">よくある質問 <a class="header-anchor" href="#よくある質問" aria-label="Permalink to &quot;よくある質問&quot;">​</a></h2><h3 id="「関係記録がない」と表示される" tabindex="-1">「関係記録がない」と表示される <a class="header-anchor" href="#「関係記録がない」と表示される" aria-label="Permalink to &quot;「関係記録がない」と表示される&quot;">​</a></h3><p>相手側であなたの記録が削除された可能性があります。再度参加申請を行ってください。</p><p><img src="'+s+'" alt="再申請" loading="lazy"></p><h3 id="参加後にファイルが見えない" tabindex="-1">参加後にファイルが見えない <a class="header-anchor" href="#参加後にファイルが見えない" aria-label="Permalink to &quot;参加後にファイルが見えない&quot;">​</a></h3><p>次を確認します。</p><ol><li>相手が申請を承認している。</li><li>相手が送信インデックスを更新している。</li><li>自分が受信インデックスを更新している。</li><li>相手の同期フォルダに共有対象のディレクトリが含まれている。</li></ol>',52)])])}const y=p(b,[["render",u]]);export{P as __pageData,y as default};
